import { PropsIconsNameCore } from '@semparar/design-system-app';

export interface ParameterPointsProgramValue {
  questions: Array<{
    question: string;
    answer: string;
  }>;
  order: number;
  icon: PropsIconsNameCore;
}

export interface ParameterPointsProgramResponse {
  dateCreated: string;
  status: number;
  category: string;
  PK: string;
  dateUpdated: string;
  value: string | ParameterPointsProgramValue;
}

export enum ParameterPointsProgramStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface ParameterPointsProgramState {
  data?: ParameterPointsProgramResponse[];
  selectedCategory?: ParameterPointsProgramResponse;
  status: ParameterPointsProgramStatus;
  pointsQuantity: number;
  conversionFactor: number;
}

import { StateCreator } from 'zustand';

import {
  createParameterPointsProgramSlice,
  ParameterPointsProgramSlice,
  createPermissionSlice,
  PermissionSlice,
  AirlineMilesSlice,
  createAirlineMilesSlice,
  createPointsExtractSlice,
  PointsExtractSlice,
  createPointsProductsSlice,
  PointsProductsSlice,
  createRescueSlice,
  RescueSlice,
  createMarketplaceSlice,
  MarketplaceSlice,
} from '../index';

export type RewardsProgramRootStore =
  ParameterPointsProgramSlice &
  PermissionSlice &
  AirlineMilesSlice &
  PointsExtractSlice &
  PointsProductsSlice &
  RescueSlice &
  MarketplaceSlice;

type Slice<T> = StateCreator<RewardsProgramRootStore, [], [], T>;
const asSlice = <T>(slice: StateCreator<RewardsProgramRootStore, [], [], T>) => slice as Slice<T>;

export function setRewardsProgramSlices<T extends RewardsProgramRootStore>(...a: Parameters<Slice<T>>) {
  return {
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(...a),
    ...asSlice<PermissionSlice>(createPermissionSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
  };
}

